%% Benchmark function handles (input x is a 1xd vector)
function [op] = selectOptimizationProblem(problem, op)

    if op.dim < 1
        warning("Dimensionality was changed to d=1 because it cannot be non-positive.");
        op.dim = 1;
    elseif op.dim > 1000
        warning("Dimensionality was changed to d=1000 as maximum allowed value.");
        op.dim = 1000;
    end

    switch problem
        case "sphere"
        % Sphere (De Jong)
        op.fun = @(x) sum(x.^2);
        op.bounds = [-5.12, 5.12];
        op.opt = zeros(1,op.dim);
        op.opt_known = true;
        op.isMin = true;
    
        case "rosenbrock"
        % Rosenbrock
        op.fun = @(x) sum(100*(x(2:end) - x(1:end-1).^2).^2 + (1 - x(1:end-1)).^2);
        op.bounds = [-2.048, 2.048];
        op.opt = ones(1,op.dim);
        op.opt_known = true;
        op.isMin = true;
        
        case "rastrigin"
        % Rastrigin
        op.fun = @(x) 10*numel(x) + sum(x.^2 - 10*cos(2*pi*x));
        op.bounds = [-5.12, 5.12];
        op.opt = zeros(1,op.dim);
        op.opt_known = true;
        op.isMin = true;

        case "vincent"
        op.fun = @(x) sum(sin(10 .* log(x)));
        op.bounds = [0.25, 10];
        op.opt = [  0.333018435784261	0.333018435784261
                    0.333018435784261	0.624228433768570
                    0.333018435784261	1.170088787851142
