                    2.193280051745030	1.170088787851142
                    2.193280051745030	2.193280051745030
                    2.193280051745030	4.111207142730554
                    2.193280051745030	7.706277258637016
                    4.111207142730554	0.333018435784261
                    4.111207142730554	0.624228433768570
                    4.111207142730554	1.170088787851142
                    4.111207142730554	2.193280051745030
                    4.111207142730554	4.111207142730554
                    4.111207142730554	7.706277258637016
                    7.706277258637016	0.333018435784261
                    7.706277258637016	0.624228433768570
                    7.706277258637016	1.170088787851142
                    7.706277258637016	2.193280051745030
                    7.706277258637016	4.111207142730554
                    7.706277258637016	7.706277258637016];
        op.opt_known = true;
        op.isMin = false;
        op.maxFE = 2.0E+05;
        
        case "ackley"
        % Ackley
        op.fun = @(x) -20*exp(-0.2*sqrt(mean(x.^2))) - exp(mean(cos(2*pi*x))) + 20 + exp(1);
        op.bounds = [-32.768, 32.768];
        op.opt = zeros(1,op.dim);
        op.opt_known = true;
        op.isMin = true;
        
        case "griewank"
        % Griewank
        op.fun = @(x) sum(x.^2)/4000 - prod(cos(x./sqrt(1:numel(x)))) + 1;
        op.bounds = [-600, 600];
        op.opt = zeros(1,op.dim);
        op.opt_known = true;
        op.isMin = true;
        
        case "schwefel"
        % Schwefel
        op.fun = @(x) 418.9829*numel(x) - sum(x .* sin(sqrt(abs(x))));
        op.bounds = [-500, 500];
        op.opt = ones(1,op.dim) * 420.9687;
        op.opt_known = true;
        op.isMin = true;
        
        case "zakharov"
        % Zakharov
        op.fun = @(x) sum(x.^2) + (0.5*(1:numel(x))*x').^2 + (0.5*(1:numel(x))*x').^4;
        op.bounds = [-5, 10];
        op.opt = zeros(1,op.dim);
        op.opt_known = true;
        op.isMin = true;
        
        case "dixon-price"
        % Dixon–Price
        op.fun = @(x) (x(1)-1)^2 + sum((2:numel(x)).*(2*x(2:end).^2 - x(1:end-1)).^2);
        op.bounds = [-10, 10];
        op.opt = ones(1,op.dim)*10; % wrong
        op.opt_known = false;
        op.isMin = true;
        
        case "levy"
        % Levy
        op.fun = @(x) ...
            (sin(pi*(1 + (x(1)-1)/4)))^2 + ...
            sum(((x(1:end-1)-1)/4).^2 .* (1 + 10*sin(pi*(1 + (x(2:end)-1)/4)).^2)) + ...
            ((x(end)-1)/4)^2 * (1 + sin(2*pi*(1 + (x(end)-1)/4))^2);
        op.bounds = [-10, 10];
        op.opt = ones(1,op.dim);
        op.opt_known = true;
        op.isMin = true;
        
        case "michalewicz"
        % Michalewicz (parameter m controls steepness; m=10 is common)
        op.fun = @(x) -sum(sin(x) .* (sin((1:numel(x)).*x.^2/pi)).^(2*10));
        op.bounds = [0, pi];
        op.opt = zeros(1,op.dim); % wrong
        op.opt_known = false;
        op.isMin = true;
        
        case "styblinski–tang"
        % Styblinski–Tang
        op.fun = @(x) 0.5*sum(x.^4 - 16*x.^2 + 5*x);
        op.bounds = [-5, 5];
        op.opt = ones(1,op.dim) * -2.903534;
        op.opt_known = true;
        op.isMin = true;

