    loc1 = 0;
    loc2 = 0;
    output = 0;

    for j = 1:size(x,2)
        for k = 1:3
            for k1 = 1:2^(k-1)
                loc2 = loc2 + 1;
                for k2 = 1:ran2(loc2)
                    loc1 = loc1 + 1;
                    if abs(x(j)) < 0.5
                        output = output + ...
                            (-6144*(-ran11(loc1))^6 + ...
                             3088*(x(j) - ran11(loc1))^4 - ...
                             392*(x(j) - ran11(loc1))^2 + 1) ...
                             / (2^(k-1) * (2 - ran12(loc1)));
                    end
                end
            end
        end
    end
end

%% CEC2013 for large scale global optimization
function ptrim = wrap_perm(pvec, Dlocal)
    % Make permutation vector of length Dlocal by truncation or tiling
    pvec = pvec(:)';
    if isempty(pvec)
        ptrim = 1:Dlocal;
        return;
    end
    if numel(pvec) >= Dlocal
        ptrim = pvec(1:Dlocal);
    else
        ptrim = repmat(pvec, 1, ceil(Dlocal/numel(pvec)));
        ptrim = ptrim(1:Dlocal);
    end
end

%% ---------------- Robust scale_blocks ----------------
function S = scale_blocks(S0, Dlocal)
% SCALE_BLOCKS  Proportionally scale integer block vector S0 so sum(S)==Dlocal.
% Works even when Dlocal < length(S0) (small dimensions).
% Returns S with only positive block sizes, sum(S) == Dlocal.

if Dlocal <= 0
    S = [];
    return;
end

S0 = S0(:)';
n = numel(S0);
% ideal (floating) allocation
ideal = S0 / sum(S0) * Dlocal;

% integer floor allocation
S = floor(ideal);

% compute remainder to distribute
rem = Dlocal - sum(S);

if rem > 0
    % distribute +1 to blocks with largest fractional parts
    frac = ideal - S;
    [~, idxs] = sort(frac, 'descend');
    k = 1;
    while rem > 0 && k <= numel(idxs)
        S(idxs(k)) = S(idxs(k)) + 1;
        rem = rem - 1;
        k = k + 1;
    end
elseif rem < 0
    % remove 1 from blocks with smallest fractional parts (or largest negative)
    frac = ideal - S;
    [~, idxs] = sort(frac, 'ascend');
    k = 1;
    while rem < 0 && k <= numel(idxs)
        if S(idxs(k)) > 0
            S(idxs(k)) = S(idxs(k)) - 1;
            rem = rem + 1;
        end
        k = k + 1;
    end
end

% remove zero-size blocks (they are meaningless)
S = S(S > 0);

% if all were removed (e.g., Dlocal < 1) then give single block with Dlocal
if isempty(S)
    S = Dlocal;
end

end


function out = sphere_handler(x, shift)
    % accepts m-by-d or 1-by-d input
    X = bsxfun(@minus, x, shift);
    out = sum(X.^2, 2);
end

function out = schwefel12_handler(x, shift)
    X = bsxfun(@minus, x, shift);
    out = f_schwefel12(X);
end

function y = f_schwefel12(X)
    % Schwefel's problem 1.2: sum_i (sum_{j<=i} x_j)^2
    c = cumsum(X, 2);
    y = sum(c.^2, 2);
end

function out = rosenbrock_handler(x, shift)
    X = bsxfun(@minus, x, shift);
    % classical Rosenbrock sum over i=1..d-1
    if size(X,2) < 2
        out = zeros(size(X,1),1);
        return;
    end
    xi = X(:,1:end-1); xnext = X(:,2:end);
    out = sum(100*(xnext - xi.^2).^2 + (xi - 1).^2, 2);
end

function out = block_wrapper(x, shift, pvec, Svec, Wvec, Rs_cell, d)
    % Generic block-wise wrapper used by many CEC2013 functions.
    %
    % x: m-by-d input. shift: 1-by-d. pvec: 1-by-d permutation.
    % Svec: vector of block sizes summing to d. Wvec: weights for blocks.
    % Rs_cell: {R25,R50,R100} (rotation matrices). 'tag' optional indicator (unused here).
    %
    % Note: rotation is applied only when block size matches 25/50/100 and a matrix exists.
    X = bsxfun(@minus, x, shift);     % m x d
    % reorder columns by permutation pvec (safe, pvec is length d)
    if ~isempty(pvec)
        X = X(:, pvec);
    end
    mrows = size(X,1);
    out = zeros(mrows,1);
    idx = 1;
    % extract rotation matrices from Rs_cell
    R25_loc  = Rs_cell{1};
    R50_loc  = Rs_cell{2};
    R100_loc = Rs_cell{3};
    for iS = 1:length(Svec)
        s = Svec(iS);
        cols = idx:(idx+s-1);
        Xi = X(:, cols); % m x s
        % apply rotation if known
        if s==25 && ~isempty(R25_loc) && all(size(R25_loc)==[25 25])
            Xi = Xi * R25_loc;
        elseif s==50 && ~isempty(R50_loc) && all(size(R50_loc)==[50 50])
            Xi = Xi * R50_loc;
        elseif s==100 && ~isempty(R100_loc) && all(size(R100_loc)==[100 100])
            Xi = Xi * R100_loc;
        else
            % leave Xi as-is for other sizes
        end
        % transform (Tosz) and weight combination
        Ti = Tosz(Xi);
        wvec = 10 .^ (6 * linspace(0,1,size(Ti,2))); % 1 x s
        Wmat = repmat(wvec, mrows, 1);
        wblock = 1;
        if ~isempty(Wvec)
            wblock = Wvec(min(iS, length(Wvec)));
        end
        out = out + wblock * sum( Wmat .* (Ti.^2), 2 );
        idx = idx + s;
    end
end

function out = overlap_wrapper(x, shift, pvec, Svec, m_overlap, Wvec, Rs_cell, mode, shifts_cell)
    % Implements overlapping subcomponents. mode == 'conforming' or 'conflicting'
    X = x; % m x d
    mrows = size(X,1);
    Dlocal = size(X,2);
    out = zeros(mrows,1);
    % cumulative sums of Svec
    C = cumsum(Svec);
    % build permutation pvec wrapped if needed
    if isempty(pvec)
        pvec = 1:Dlocal;
    end
    for i = 1:length(Svec)
        Si = Svec(i);
        Ci = C(i);
        startIndex = Ci - (i-1)*m_overlap - Si + 1;
        endIndex   = Ci - (i-1)*m_overlap;
        idxRange = startIndex:endIndex;
        % wrap into 1..Dlocal
        idxWrapped = mod(idxRange-1, Dlocal) + 1;
        idx = pvec(idxWrapped);
        Y = X(:, idx); % m x Si
        % shift selection
        if strcmp(mode,'conforming')
            shift_i = shift(idx);
            Z = bsxfun(@minus, Y, shift_i);
        else % conflicting: optional per-block shifts provided via shifts_cell
            if nargin>=9 && ~isempty(shifts_cell) && length(shifts_cell)>=i && ~isempty(shifts_cell{i})
                si = shifts_cell{i};
                si = si(1:Si);
                Z = bsxfun(@minus, Y, si);
            else
                shift_i = shift(idx);
                Z = bsxfun(@minus, Y, shift_i);
            end
        end
        % rotate if available
        if ~isempty(Rs_cell) && length(Rs_cell)>=i && ~isempty(Rs_cell{i}) && size(Rs_cell{i},1)==Si
            Z = Z * Rs_cell{i};
        end
        Ti = Tasy(Tosz(Z), 0.2);
        Ti = (Lambda(Si,10) * Ti')';
        wblock = 1;
        if ~isempty(Wvec), wblock = Wvec(min(i, length(Wvec))); end
        out = out + wblock * sum(Ti.^2, 2);
    end
end

function Y = Tosz(X)
    % elementwise Tosz transform
    Y = zeros(size(X));
    nz = (X~=0);
    X1 = zeros(size(X));
    X1(nz) = log(abs(X(nz)));
    C1 = 5.5 + 4.5*(X>0);
    C2 = 3.1 + 4.8*(X>0);
    Y = sign(X) .* exp( X1 + 0.049*( sin(C1.*X1) + sin(C2.*X1) ) );
end

function Y = Tasy(X, beta)
    if nargin<2, beta = 0.2; end
    [mX,nX] = size(X);
    idx = repmat(1:nX, mX, 1);
    pos = X > 0;
    exponent = 1 + beta * (idx-1) / max(1,nX-1) .* sqrt(idx./nX);
    Y = X;
    Y(pos) = X(pos) .^ exponent(pos);
end

function L = Lambda(n, alpha)
    if nargin<2, alpha = 1e6; end
    exponents = (0:n-1)' ./ max(1,n-1);
    diagv = alpha .^ (exponents/2);
    L = diag(diagv);
end

function data = loadDataCEC2015(f)
    load("CEC2013_LGO_rotations.mat");
    switch f
